import React, { useState, useRef } from 'react';
import { Icons } from '../constants';
import { auditRecipeWithAI } from '../services/geminiService';
import { AuditResult } from '../types';
import FoodLoader from '../components/FoodLoader';
import AuditReport from '../components/AuditReport';

const Auditor: React.FC = () => {
  const [inputText, setInputText] = useState('');
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingStatus, setLoadingStatus] = useState('');
  const [result, setResult] = useState<AuditResult | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAudit = async () => {
    if (!inputText && !selectedImage) return;

    setIsLoading(true);
    setError(null);
    setLoadingStatus('Initializing Digital Care Team...');

    try {
      // Simulate Agent sequence for UX
      setTimeout(() => setLoadingStatus('Doctor Agent: Analyzing macros & GI...'), 1000);
      setTimeout(() => setLoadingStatus('Chef Agent: Searching local markets for swaps...'), 3500);

      const auditData = await auditRecipeWithAI(inputText || "Analyze this image", !!selectedImage, selectedImage || undefined);

      // Ensure the "simulation" lasts at least 4.5 seconds so the user sees the messages
      setTimeout(() => {
        setResult(auditData);
        setIsLoading(false);
      }, 5000);

    } catch (err: any) {
      console.error(err);
      setError("Failed to audit recipe. Please check your connection or API key.");
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-[60vh] flex flex-col items-center justify-center">
        <FoodLoader status={loadingStatus} />
      </div>
    );
  }

  if (result) {
    return <AuditReport result={result} onReset={() => { setResult(null); setInputText(''); setSelectedImage(null); }} />;
  }

  return (
    <div className="max-w-2xl mx-auto space-y-8 animate-fade-in-up">
      <div className="text-center space-y-2">
        <h1 className="text-3xl font-bold text-gray-900">Recipe Auditor</h1>
        <p className="text-gray-500">
            Upload a photo of your meal or paste a recipe. Our dual-agent AI (Doctor & Chef) will check it for safety and flavor.
        </p>
      </div>

      <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 space-y-6">
        {/* Input Type Selection */}
        <div className="space-y-4">
            <label className="block text-sm font-medium text-gray-700">What are you eating?</label>

            {/* Image Area */}
            <div 
                className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-colors ${selectedImage ? 'border-primary bg-teal-50' : 'border-gray-300 hover:border-gray-400'}`}
                onClick={() => fileInputRef.current?.click()}
            >
                {selectedImage ? (
                    <div className="relative">
                        <img src={selectedImage} alt="Preview" className="max-h-64 mx-auto rounded-lg shadow-md" />
                        <button 
                            onClick={(e) => { e.stopPropagation(); setSelectedImage(null); }}
                            className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 shadow-sm hover:bg-red-600"
                        >
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>
                ) : (
                    <div className="flex flex-col items-center space-y-2 text-gray-500">
                        <Icons.Upload />
                        <span>Click to upload a food photo</span>
                    </div>
                )}
                <input 
                    type="file" 
                    accept="image/*" 
                    className="hidden" 
                    ref={fileInputRef}
                    onChange={handleImageUpload}
                />
            </div>

            <div className="relative">
                <div className="absolute inset-0 flex items-center">
                    <div className="w-full border-t border-gray-200"></div>
                </div>
                <div className="relative flex justify-center text-sm">
                    <span className="px-2 bg-white text-gray-500">OR</span>
                </div>
            </div>

            {/* Text Area */}
            <div>
                <textarea
                    className="w-full rounded-xl border-gray-200 shadow-sm focus:border-primary focus:ring focus:ring-primary focus:ring-opacity-20 p-4"
                    rows={4}
                    placeholder="e.g., Sinigang na Baboy with 2 cups of white rice..."
                    value={inputText}
                    onChange={(e) => setInputText(e.target.value)}
                />
            </div>
        </div>

        {error && (
            <div className="p-3 bg-red-50 text-red-700 rounded-lg text-sm">
                {error}
            </div>
        )}

        <button
            onClick={handleAudit}
            disabled={!inputText && !selectedImage}
            className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition-all transform hover:scale-[1.02] active:scale-95 ${(!inputText && !selectedImage) ? 'bg-gray-300 cursor-not-allowed' : 'bg-gradient-to-r from-primary to-emerald-600 hover:shadow-xl'}`}
        >
            Start AI Audit
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="bg-blue-50 p-4 rounded-xl flex items-start gap-3">
            <div className="text-blue-600 mt-1"><Icons.Doctor /></div>
            <div className="text-sm">
                <p className="font-semibold text-blue-900">Medical Safety</p>
                <p className="text-blue-700">Strict checking against diabetic guidelines.</p>
            </div>
        </div>
        <div className="bg-orange-50 p-4 rounded-xl flex items-start gap-3">
            <div className="text-orange-600 mt-1"><Icons.Chef /></div>
            <div className="text-sm">
                <p className="font-semibold text-orange-900">Culinary Swaps</p>
                <p className="text-orange-700">Tasty alternatives found in local stores.</p>
            </div>
        </div>
      </div>
    </div>
  );
};

export default Auditor;

